code = """import json
import re

with open(locals()['var_function-call-5532324995527452861'], 'r') as f:
    papers = json.load(f)

with open(locals()['var_function-call-3656629748920796517'], 'r') as f:
    citations = json.load(f)

# Build citation map
citation_map = {}
for c in citations:
    t = c['title']
    count = int(c['citation_count'])
    if t not in citation_map:
        citation_map[t] = 0
    citation_map[t] += count

candidates = []

for p in papers:
    text = p.get('text', '')
    filename = p['filename']
    title = filename.replace('.txt', '')
    
    # Check domain: "physical activity"
    # Also check title just in case
    has_pa = "physical activity" in text.lower() or "physical activity" in title.lower()
    
    if not has_pa:
        continue

    # Check Year 2016
    # Look for 2016 in first 2000 chars
    head = text[:2000]
    
    # Patterns for 2016:
    # - "2016"
    # - "'16" near "CHI" or "UbiComp" etc.
    # - "September 12-16, 2016"
    # - "Copyright 2016"
    
    is_2016 = False
    if "2016" in head:
        is_2016 = True
    elif re.search(r"'\s*16", head): # matches '16
        is_2016 = True
        
    # Double check if 2016 is actually the publication year
    # Some papers might cite 2016 papers in the abstract? Unlikely in header.
    # But let's assume if 2016 is in header, it's the year.
    
    # Also check for 2015 or 2017 to exclude?
    # If both 2015 and 2016 appear, logic is harder.
    # But usually only the conference year appears prominently.
    
    if is_2016:
        candidates.append(title)

# Get citation counts for candidates
results = []
for t in candidates:
    c = citation_map.get(t, 0)
    results.append({"title": t, "total_citation_count": c})

print("__RESULT__:")
print(json.dumps(results))"""

